executeFunc((function productsSignPdf(){const fileAddCollectionButton=document.getElementById("file-add-collection");if(fileAddCollectionButton===null||typeof fileAddCollectionButton==="undefined"){return false}fileAddCollectionButton.addEventListener("click",addFile);return true}));function addFile(){let newForm=this.dataset.prototype;let index=this.dataset.index*1;let call=this.dataset.call*1;let collection=this.dataset.collection;newForm=newForm.replace(/__supply_file__/g,index);let div=document.createElement("div");div.innerHTML=newForm;div.id="item_product_supply_files_form_files_"+index;div.classList.add("mb-3");let $collection=document.getElementById(collection);$collection.append(div);div.querySelector(".del-item-file")?.addEventListener("click",deleteFile);this.dataset.index=(index+1).toString()}function deleteFile(){document.getElementById("item_"+this.dataset.delete).remove()}